        if(n == 0)

            return 0;



        bitset<16> initial, final;

        for(int i=0; i<n; ++i){

            char c;

            cin >> c;

            initial[i] = (c == 'B');

        }

        for(int i=0; i<n; ++i){

            char c;

            cin >> c;

            final[i] = (c == 'B');

        }



        vector<vector<int> > memo(1<<n, vector<int>(n, INF));

        multimap<int, pair<bitset<16>, int> > mm;

        for(int i=0; i<n; ++i){

            memo[initial.to_ulong()][i] = 0;

            mm.insert(make_pair(0, make_pair(initial, i)));

        }



        for(;;){

